		const _len = logLines.length;
		if (autoScroll && logContainer) {
			// Defer so DOM updates before we measure
			Promise.resolve().then(() => {
				if (logContainer) logContainer.scrollTop = logContainer.scrollHeight;
			});
		}
	});

