		const details = inputText(event.inputs);
		const summary = toolInputSummary(event.inputs);
		if (summary && details) return `${event.name ?? 'tool'} path ${summary} ${details}`;
		return details ? `${event.name ?? 'tool'} ${details}` : (event.name ?? 'tool');
	}

